import { describe, it, expect } from "vitest";
import { calculatePremium } from "./premium.js";

describe("Premium Calculation", () => {
  it.todo("empty item list → premium 5 G (processing fee only)");
  it.todo("single sword, new customer (0 years, first contract) → 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("single amulet, new customer → 71 G (60 + 6 + 5)");
  it.todo("single staff, new customer → 93 G (80 + 8 + 5)");
  it.todo("single potion, new customer → 49 G (40 + 4 + 5)");
  it.todo("single rune, new customer → 33 G (25 + 2.5 + 5 → ceil 33)");
  it.todo("single moonstone, new customer → 33 G (25 + 2.5 + 5 → ceil 33)");
  it.todo("2 runes (no block) → 60 G (50 base + 5 first-insurance + 5 fee)");
  it.todo("3 runes (block applies) → 71 G (60 base + 6 first-insurance + 5 fee)");
  it.todo("4 runes (no block, block requires exactly 3) → 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("7 runes → 198 G (175 base + 17.5 first-insurance + 5 = 197.5 → ceil 198)");
  it.todo("2 runes + 1 moonstone (no block, different types) → 88 G (75 base + 7.5 first-insurance + 5 = 87.5 → ceil 88)");
  it.todo("3 runes + 3 moonstones (two separate blocks) → 137 G (120 base + 12 first-insurance + 5)");
  it.todo("cursed sword, new customer → 165 G (100 base + 50 curse + 10 first-insurance + 5)");
  it.todo("sword enchantment 5 (high enchantment), new customer → 145 G (100 base + 30 enchant + 10 first-insurance + 5)");
  it.todo("sword enchantment 4 (no high enchantment), not cursed, new customer → 115 G");
  it.todo("cursed sword enchantment 7, new customer → 195 G (100 base + 50 curse + 30 enchant + 10 first-insurance + 5)");
  it.todo("cursed sword + plain amulet, new customer → 231 G (160 base + 50 curse + 16 first-insurance + 5)");
  it.todo("long-standing customer (exactly 2 years), single sword, first contract → 95 G (100 base - 20 loyalty + 10 first-insurance + 5)");
  it.todo("long-standing customer (3 years), single sword, first contract → 95 G");
  it.todo("follow-up contract (second quote), single sword, 0 years → 100 G (100 base + 10 first-insurance - 15 follow-up + 5)");
  it.todo("long-standing customer (3 years), second contract, cursed sword enchantment 7 → 160 G (integration example)");
  it.todo("premium rounding up: intermediate fraction kept, final rounds up → e.g. 197.5 G → 198 G (verified via 7 runes)");
});

import { describe, it, expect } from "vitest";
import { calculatePayout } from "./claim.js";

describe("Claim Payout Calculation", () => {
  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 G (500 - 100 deductible)");
  it.todo("rune damage 200 (no enchantment/material special clauses) → payout 100 G (200 - 100 deductible)");
  it.todo("dragon material sword enchantment 5, damage 800 → payout 700 G (full reimbursement, then deductible: 800 - 100)");
  it.todo("steel sword enchantment 9, damage 1000 → payout 400 G (50% rule applies, then deductible: 500 - 100)");
  it.todo("dragon material sword enchantment 9, damage 1000 → payout 400 G (both clauses, 50% rule wins: 500 - 100)");
  it.todo("dragon material sword enchantment 8, damage 1000 → payout 400 G (high enchant clause applies, then deductible)");
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible per item: 400 + 200)");
  it.todo("two swords insured, dragon damages both → each has own deductible");
  it.todo("two swords insured but three sword damages claimed → error (more damages than policy covers for that type)");
  it.todo("policy cap: sword insured (cap 2000), two successive claims of 1500 each → first: 1400, cap: 600; second: 600, cap: 0");
  it.todo("payout rounding down: 350.5 G → 350 G");
});

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export function calculatePremium(
  items: Item[],
  yearsWithMHPCO: number,
  contractNumber: number
): number {
  throw new Error("not implemented");
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface PolicyItem {
  type: string;
  material?: string;
  enchantment?: number;
}

export function calculatePayout(
  policyItems: PolicyItem[],
  damages: Damage[],
  insuranceSum: number,
  remainingCap: number
): { payout: number; remainingCap: number } {
  throw new Error("not implemented");
}

